-- Lote 4: História da Igreja, Práticas Erradas, Santidade, Convite
INSERT INTO ai_knowledge_base (category, topic, core_teaching, bible_references, summary, keywords) VALUES

('História da Igreja', 'A Igreja Antes de Constantino',
'A Igreja Católica não nasceu com Constantino — foi fundada por Cristo, organizada pelos apóstolos e preservada pelos mártires. Mais de 200 anos antes de Constantino, cristãos já celebravam Eucaristia, tinham bispos e credo definido. Inácio de Antioquia (107) usou o termo "Igreja Católica". Justino Mártir (155) descreveu a Missa. O Édito de Milão (313) legalizou o cristianismo — não o criou. Linha do tempo: Pentecostes (33), destruição do Templo (70), Inácio usa "católica" (107), escritos de Irineu e Tertuliano (séc. II-III), legalização (313), Concílio de Niceia (325). A missão é universal (katholikós = para todos). A Igreja do Deus vivo é coluna e sustentáculo da verdade (1Tm 3:15).',
ARRAY['At 2:42','1Tm 3:15','Mt 28:19-20','2Ts 2:15'],
'A Igreja Católica existe desde o século I, fundada por Cristo. Constantino apenas legalizou o que já existia há 300 anos.',
ARRAY['constantino','igreja primitiva','história','católica','mártires','concílio','niceia']),

('História da Igreja', 'Erros Históricos e Retratação',
'A Igreja é santa por sua origem (Cristo é a cabeça), mas formada por pecadores. Na parábola do joio e do trigo (Mt 13:24-30), Jesus ensina que bem e mal coexistem até o juízo. Escândalos históricos: Indulgências — origem legítima (remissão de penas temporais), mas houve abusos no séc. XVI; o Concílio de Trento condenou e proibiu tais abusos. Inquisições — surgiram para combater heresias; pesquisas sérias mostram números muito menores que a propaganda anticatólica. Cruzadas — respostas a séculos de ataques aos cristãos e lugares sagrados; houve excessos, mas também devoção genuína. No Jubileu 2000, João Paulo II pediu perdão publicamente por falhas históricas — a única instituição cristã global a fazer isso. Erros de membros não invalidam a missão divina da Igreja.',
ARRAY['Mt 13:24-30','Mt 16:18','Mt 18:7','Tg 5:16','1Jo 1:8-9','Pv 28:13','Mt 5:23-24'],
'A Igreja reconhece erros de seus membros sem mudar sua doutrina. João Paulo II pediu perdão publicamente. Erros humanos não anulam a missão divina.',
ARRAY['erros','indulgências','inquisição','cruzadas','retratação','perdão','joão paulo II','história']),

('História da Igreja', 'Frutos da Igreja Católica',
'Jesus deu critério simples: "Pelos seus frutos os conhecereis" (Mt 7:16). Educação: fundou as primeiras universidades (Paris, Bolonha, Oxford), preservou manuscritos clássicos, produziu cientistas como Mendel (genética) e Lemaître (Big Bang). Saúde: criou os primeiros hospitais organizados; hoje mantém ~5.500 hospitais, 18.000 clínicas, 16.000 lares. Catholic Relief Services atua em 110+ países atendendo ~130 milhões de pessoas. Caritas Internationalis: 162 organizações em 200 países. Arte: canto gregoriano, polifonia, catedrais góticas, Michelangelo, Rafael. Transformação social: movimentos contra escravidão, fim de sacrifícios humanos, alfabetização e medicina em povos isolados. A Igreja permanece o maior instrumento de transformação humana da história.',
ARRAY['Mt 7:16','Mt 25:35-36','Tg 1:27','At 4:32-35','Ef 2:10'],
'Pelos frutos: universidades, hospitais, ciência, arte, caridade global. A Igreja produziu frutos civilizacionais mensuráveis ao longo de 2000 anos.',
ARRAY['frutos','universidades','hospitais','ciência','caridade','arte','educação','história']),

('Vida Cristã', 'Evangelho da Prosperidade - Erro',
'O Evangelho não é contrato de investimento. Jesus disse: "Não podeis servir a Deus e ao dinheiro" (Mt 6:24). O amor ao dinheiro é raiz de todos os males (1Tm 6:9-10). Pedro disse ao coxo: "Não tenho prata nem ouro, mas o que tenho te dou" (At 3:6). A bênção de Deus é gratuita (Is 55:1). Erros do evangelho da prosperidade: reduz Deus a financiador, usa ofertas como "chave" de milagres, promete bênçãos materiais quando Cristo prometeu cruz e vida eterna, mensura espiritualidade pelo patrimônio. Surgiu no séc. XX nos EUA (Word of Faith, Confissão Positiva), chegou ao Brasil nos anos 1970-80 com neopentecostalismo. Consequências: fiéis frustrados, falsos mestres enriquecendo, descrédito do cristianismo.',
ARRAY['Mt 6:24','1Tm 6:9-10','At 3:6','Is 55:1','Mt 6:19-21'],
'O evangelho da prosperidade é distorção: transforma fé em comércio. A bênção de Deus é gratuita e o cristão é chamado a carregar a cruz, não acumular riqueza.',
ARRAY['prosperidade','dinheiro','neopentecostalismo','erro','comércio da fé','ofertas','mammon']),

('Vida Cristã', 'Emocionalismo e Manipulação - Erro',
'A adoração verdadeira é em espírito e verdade (Jo 4:24), não performance. Paulo exige ordem e edificação no culto (1Cor 14:26,33,40). O culto racional (logiké latreía, Rm 12:1) é espiritual porque racional e obediente. O Espírito Santo é Pessoa divina, não energia. Sua obra: convencer do pecado, guiar à verdade, santificar, gerar unidade. Sinais ordinários: amor concreto, obediência, paz estável, humildade. Emoção legítima nasce da Palavra e leva à conversão; manipulação usa repetição vazia, indução de choro/gritos, pressão de grupo. Pentecostes gerou doutrina, sacramentos e vida santa, não espetáculo. Davi dançou dentro da liturgia, não no improviso. Fruto sem show = Espírito em ação; show sem fruto = catarse.',
ARRAY['Jo 4:23-24','1Cor 14:26','1Cor 14:33','1Cor 14:40','Rm 12:1','Gl 5:22-23','Mt 7:16','1Jo 4:1','1Ts 5:19-21'],
'Fé não é teatro. O Espírito Santo gera frutos estáveis (amor, paz, conversão), não espetáculo emocional. O culto deve ser racional, ordenado e verdadeiro.',
ARRAY['emocionalismo','manipulação','espírito santo','culto','ordem','discernimento','frutos','pentecostes']),

('Vida Cristã', 'Superstição vs Sacramentais',
'Sacramentais (água benta, escapulário, medalha, cruz) são sinais sagrados que dispõem o coração à graça pela fé — não têm poder automático. Deus usou objetos como meios: lenços de Paulo curavam (At 19:11-12), serpente de bronze curava quem olhava com fé (Nm 21:8-9). Mas quando Israel adorou a serpente, Ezequias a destruiu (2Rs 18:4). O sacramental aponta para Deus; o amuleto substitui Deus. Superstição é atribuir poder mágico ao objeto. Uso correto: sinal de fé que lembra de viver perto de Deus. Uso errado: "proteção garantida" sem oração nem conversão. Sacramentos conferem graça ex opere operato (por Cristo); sacramentais conferem graça pela disposição da fé.',
ARRAY['At 19:11-12','Nm 21:8-9','2Rs 18:4','1Sm 16:7'],
'Sacramentais são meios de fé, não amuletos mágicos. O valor está no que apontam (Deus), não no material. Superstição é trocar Criador pela criatura.',
ARRAY['sacramentais','superstição','amuleto','água benta','escapulário','medalha','fé','objetos sagrados']),

('Vida Cristã', 'Chamado à Santidade',
'A santidade é mandamento, não sugestão. "Sede santos, porque Eu sou santo" (1Pe 1:16). "Sem santificação ninguém verá o Senhor" (Hb 12:14). Jesus: "Sede perfeitos como o Pai" (Mt 5:48) — teleios = completo, maduro, crescimento constante. O fruto do Espírito (Gl 5:22-23) é único e se manifesta em várias virtudes: amor, alegria, paz, paciência, benignidade, bondade, fidelidade, mansidão, domínio próprio. A santidade é vivida nas relações diárias: humildade, mansidão, paciência, unidade (Ef 4:1-3). No hebraico, ser santo (qadosh) significa ser separado para Deus. A comunidade cristã primitiva entendia santidade como testemunho vivo que atraía outros para Cristo.',
ARRAY['1Pe 1:16','Hb 12:14','Gl 5:22-23','Mt 5:48','Ef 4:1-3'],
'Santidade é mandamento universal: ser separado para Deus e produzir frutos do Espírito. Não é para poucos — é chamado a todo cristão.',
ARRAY['santidade','fruto do espírito','virtudes','conversão','vida cristã','mandamento']);
